import React from "react";
import { useNavigate } from "react-router-dom";

function Login() {
  const navigate = useNavigate();

  return (
    <div style={styles.container}>

      {/* Header */}
      <header style={styles.header}>
        <h2>DocBook</h2>
      </header>

      {/* Login Card */}
      <div style={styles.main}>
        <div style={styles.card}>
          <h2>Login</h2>

          <input
            type="text"
            placeholder="Email"
            style={styles.input}
          />

          <input
            type="password"
            placeholder="Password"
            style={styles.input}
          />

          <button style={styles.button}>Login</button>

          {/* ✅ Updated Register Link */}
          <p style={styles.text}>
            Don't have an account?{" "}
            <span
              style={styles.link}
              onClick={() => navigate("/register")}
            >
              Register
            </span>
          </p>

        </div>
      </div>

      {/* Footer */}
      <footer style={styles.footer}>
        <p>© 2026 MediCare. All rights reserved.</p>
      </footer>

    </div>
  );
}

export default Login;

const styles = {
  container: {
    fontFamily: "Segoe UI, sans-serif",
    height: "100vh",
    display: "flex",
    flexDirection: "column",
  },

  header: {
    backgroundColor: "#2563EB",
    color: "white",
    padding: "15px",
    textAlign: "center",
  },

  main: {
    flex: 1,
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    backgroundColor: "#f3f6fb",
  },

  card: {
    backgroundColor: "white",
    padding: "35px",
    borderRadius: "12px",
    width: "320px",
    textAlign: "center",
    boxShadow: "0 10px 25px rgba(0,0,0,0.08)",
  },

  input: {
    width: "100%",
    padding: "10px",
    margin: "10px 0",
    borderRadius: "6px",
    border: "1px solid #ddd",
  },

  button: {
    width: "100%",
    padding: "12px",
    backgroundColor: "#2563EB",
    color: "white",
    border: "none",
    borderRadius: "6px",
    cursor: "pointer",
    marginTop: "10px",
    fontWeight: "600",
  },

  text: {
    marginTop: "15px",
    fontSize: "14px",
  },

  link: {
    color: "#2563EB",
    fontWeight: "600",
    cursor: "pointer",
  },

  footer: {
    backgroundColor: "#2563EB",
    color: "white",
    textAlign: "center",
    padding: "10px",
  },
};
